            Tags = """["lots","traceability","quality","reference"]""",
            ContentJson = """{"title":"Production Lots Field Reference","groups":[{"heading":"Lot Record Fields","items":[{"label":"Lot Number","value":"Up to 100 characters. Filled in for you if you leave it blank (like LOT-20260415-001). You can type your own for a custom numbering scheme."},{"label":"Part (required)","value":"The part this lot is for. Every lot is tied to exactly one part."},{"label":"Quantity (required)","value":"Must be more than 0. Fractional amounts are allowed, so you can record material measured by weight, volume, or length — for example 12.5 kg or 3.75 m. The detail panel shows the exact amount you entered, decimals and all, so nothing gets rounded off."},{"label":"Job (optional)","value":"The production job that created this lot. Left blank for lots received from a vendor with no job."},{"label":"Production Run (optional)","value":"The specific production run within a job. More precise than tracking at the job level."},{"label":"Purchase Order Line (optional)","value":"The purchase order line the material came in on. Used when the lot comes from receiving vendor material."},{"label":"Supplier Lot Number (optional)","value":"Up to 100 characters. The vendor's own batch number. Key for holding a supplier accountable and for recall investigations."},{"label":"Expiration Date (optional)","value":"For materials with a shelf life. Left blank for materials that do not expire."},{"label":"Notes (optional)","value":"Up to 2000 characters. Free-form notes: storage conditions, deviations, special handling."},{"label":"Created","value":"Set automatically when the lot is created. Used to sort lots by date."},{"label":"Created By","value":"Set automatically to whoever created the lot. Part of the audit trail."}]},{"heading":"What You Can Do with Lots","items":[{"label":"View the list","value":"See all lots, and filter by part or by job. Search matches the lot number, the supplier's lot number, and the part number. Newest lots show first."},{"label":"Create a lot","value":"Pick a part and enter a quantity (both required). A linked job, production run, purchase order line, supplier lot, expiration date, and notes are optional. The lot number is filled in for you if you leave it blank."},{"label":"Trace a lot","value":"Look up a lot number to see its whole chain: the part, linked jobs, production runs, purchase orders (with the vendor), bin locations (with quantities), and QC inspections (with inspector, status, and date)."}]},{"heading":"Traceability View (Lot Detail Panel)","items":[{"label":"Header — Part","value":"The part this lot is for, shown at the top of the trace panel."},{"label":"Header — Quantity","value":"The lot quantity, shown exactly as entered so fractional amounts by weight, volume, or length read correctly instead of being rounded."},{"label":"Header — Supplier Lot","value":"The vendor's batch number. Shown only when one was recorded."},{"label":"Header — Expires","value":"The expiration date. Shown only when one was set."},{"label":"Trace History","value":"One timeline in date order, not separate lists. Each entry shows a type, reference number, description, and date. Entry types are job, production run, purchase order, bin location, and QC inspection, each with its own icon. All five kinds are woven into this single stream rather than shown in five separate sections."}]},{"heading":"What's Required","items":[{"label":"Part","value":"Required. Must be a real part."},{"label":"Quantity","value":"Required. Must be more than 0. Fractional amounts are allowed — not just whole units."},{"label":"Lot Number","value":"Optional. Up to 100 characters. If left blank, filled in as LOT-YYYYMMDD-NNN."},{"label":"Supplier Lot Number","value":"Optional. Up to 100 characters."},{"label":"Notes","value":"Optional. Up to 2000 characters."},{"label":"Expiration Date","value":"Optional. Must be a valid date if you enter one."}]},{"heading":"Who Can Use Lots","items":[{"label":"Who has access","value":"Admins, Managers, Engineers, and Production Workers. All four can create lots and run traceability lookups."},{"label":"Deleting a lot","value":"A deleted lot is hidden from the lists and lookups but never truly erased — the record is kept for the audit trail and compliance."}]},{"heading":"How the Lot Number Is Built","items":[{"label":"Pattern","value":"LOT-YYYYMMDD-NNN"},{"label":"Prefix","value":"LOT- (always the same)"},{"label":"Date part","value":"YYYYMMDD — the date the lot was created (for example 20260415)"},{"label":"Sequence","value":"NNN — a 3-digit counter that restarts each day (001, 002, ... 999)"},{"label":"Example","value":"LOT-20260415-003 = the third lot created on April 15, 2026"},{"label":"Your own number","value":"Type your own lot number when creating the lot to skip the automatic one. Handy for a customer's or an industry's numbering scheme."}]},{"heading":"How Lots Connect to Other Records","items":[{"label":"Part","value":"Required. The part this lot tracks — shown by its part number and description."},{"label":"Job","value":"Optional. The production job that created or used this lot — shown by its job number and title."},{"label":"Production Run","value":"Optional. The specific production run — shown by its run number and status."},{"label":"Purchase Order Line","value":"Optional. The purchase order line the material was received on — shows the PO number and the vendor."},{"label":"Bin Location","value":"Inventory bins can be tagged with a lot number, so you can see which lot sits in which bin."},{"label":"QC Inspection","value":"Quality inspections are tied to a lot by its lot number, so you can see which inspections covered this lot."}]}]}"""
        });

