            Summary = "Deeper notes for experienced lot users: why lots are create-and-trace not edit-in-place, what a deleted lot really means, when the Lots screen is hidden, sharing a lot link, scanning a lot label, and why a bin can go missing from a trace.",
            ContentType = TrainingContentType.Reference,
